export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "19:05。基線寫完了。佐伯把那張兩欄卡片收進透明套，和其他家屬的資料放在一起。他沒有宣布「又一個共同案例」。他只是把筆蓋扣上，看了一眼桌面。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他伸手，翻開桌上一個灰色資料夾。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯封面朝下放了快半小時。從我進來的時候就朝下。他不是忘了。他是故意等我先把看過什麼說清楚，才翻。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "資料夾封面是普通的灰色。沒有標籤。沒有印刷字。像文具店買的那種最便宜的款式。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯把封面翻開。內側。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "左下角。小字。原子筆寫的。筆跡有點淡，像寫了又擦過一次。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "四個字。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第七曙光。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第七曙光。這是名字。這群人的名字。不是門外那張A4紙寫的「失蹤青少年家屬資料整理會」。那是給外人看的。這個才是裡面的。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著那四個字。筆跡不是佐伯的。更圓。更慢。像一個不習慣寫字的人用力描出來的。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "這不是組織。也沒有登記。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃的聲音很輕。像在補一句她已經補過很多次的話。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "最早只是一個資料夾的名字。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她頓了一下。像在挑哪些可以說，哪些還不到時候。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "「第七」是因為孩子們的東西裡一直出現七條線。不是我們取的。是他們畫的。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "「曙光」是後來有人加的。哪個家屬我先不說。加上去之後就改不掉了。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.MinaseYoshino_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她沒有說「曙光」是什麼意思。她只說了誰加的。加了之後改不掉。可是為什麼是這兩個字？她跳過了。不是忘了。是這個名字的來源，連他們自己都沒有一個所有人都同意的版本。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯一直沒有碰那個資料夾。他把手收回來，放在桌面上。指節有點白。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "我討厭這個名字。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.SaekiTatsuya_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說得很平。但那個「討厭」不是客氣。是已經反對了很多次、反對到沒有力氣再解釋、但還是不肯讓步的那種討厭。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "說出去，別人只會覺得我們在等世界末日。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.SaekiTatsuya_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間裡有人低頭。有人沒有反應。有人把便利商店飯糰的包裝紙捏了一下。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.FujikawaMari, character: "藤川真理", dialogue: "可孩子們一直說會亮。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.FujikawaMari_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "藤川真理的聲音不大。但很穩。像她已經在心裡對著這句話反覆確認過，確認到它變成了一塊她不肯放手的東西。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "說過，不代表我們知道那是什麼。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把這句話說完，就不再往下接了。不是因為他贏了這句。是因為他知道再說下去也不會有結果。這個房間裡有人要證據，有人要希望。他只能守住那一條線：說過的東西可以記錄，但不能因為說過就當成答案。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他不信。不是不信孩子。是不信「會亮」這三個字能證明任何事。他要的是外面的人在那一天以前就收到過的東西。夢話不算。圖不算。除非有個不認識這些孩子的人，在他們失蹤以前就留下了紀錄。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯把資料夾完全攤開。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪這才看見裡面的東西。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是一份文件。是很多份。縮圖。影本。掃描列印。用迴紋針別成幾疊。每一疊右上角貼著一張小標籤，寫著代號和日期。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看見的第一張縮圖。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑色海。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是悠真畫的那張。不是水瀨葵畫的那張。是另一張。筆觸更亂。線條更急。像有人半夜醒來，抓到什麼就用什麼畫。海面也是黑的。沒有反光。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯又一個。又一個畫了黑色海的孩子。我不認識這個筆觸。我不認識這個孩子。可是海是一樣的。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的視線往旁邊移。下一張縮圖。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "倒月。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是畫的。是印的。像從某份問卷或表格上掃描下來的。月亮倒掛在紙面上方。旁邊有幾行手寫字，被影印機吃掉了一半，看不清楚。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "再旁邊。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "線條。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "七條。直的。平行。畫在一張看起來像學校講義背面的紙上。紙的正面有印刷字，被折過去了，只露出背面那七條線。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯倒月。線條。黑色海。三個東西。分開出現在不同孩子的材料裡。不是同一張圖。是同一組東西被拆開了。有人只畫了海。有人只畫了倒月。有人只畫了線。可是它們屬於同一個——", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有把那個詞想完。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不行。不能現在就想「同一個什麼」。佐伯剛才說的。像不等於來源一樣。我看過悠真的圖。我看過葵的圖。我現在看到這些縮圖，腦子會自動把它們拼起來。可是我拼的方式不一定對。我可能只是在把已經見過的東西，套到還沒見過的東西上。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把視線從縮圖上移開。看了一眼桌面。那些便利商店飯糰。那些醫院繳費單。那個把紙本排班表攤在膝上的人。那個透明套裡的交通卡。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間裡坐的是家人。不是教徒。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "可是那個資料夾裡面，躺著一個叫「第七曙光」的名字。和一片反覆出現的、沒有反光的黑色海。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "每個家庭對這個名字的意思，理解都不一樣。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃又補了一句。像她怕澪把這四個字當成某種統一的信仰宣言。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "有人覺得「第七」是第七天。有人覺得是七條線。有人覺得「曙光」是孩子們說的亮光。有人覺得只是名字，沒有別的意思。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "我不反對他們私下這樣想。我反對的是把它當成一個可以對外說的名字。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看了澪一眼。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "妳今天在這裡聽到這四個字。出了這個房間，它不存在。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在設界線。不是威脅。是保護。這個名字一旦出去，警察會覺得他們是邪教。記者會覺得他們在等末日。研究單位會有更多理由拒絕回覆。他不是討厭這個名字本身。他是討厭這個名字會引來的東西。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪點了一下頭。很輕。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "19:20。資料夾攤在桌上。灰色封面。內側四個小字。裡面是十幾個孩子留下的縮圖。黑色海。倒月。七條線。被迴紋針別成幾疊。被太多人翻過。被太多制度說「不能算證據」。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後被一群普通的家屬，放進一個不討喜的名字底下，繼續保存。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯把資料夾推到桌面中間。不偏向任何人。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "接下來看案例。不輪流講故事。看卡片。", background: Background.Chapter_11_Ch11_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從資料夾後方抽出一疊去識別化的案例卡。白紙。黑字。沒有照片。沒有全名。只有代號、年齡、失蹤日數、材料類型與證據等級。", background: Background.Chapter_11_Ch11_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "19:35。燈還是正常亮度。投影幕還是空白。房間裡沒有儀式。沒有祈禱。只有一個男人把卡片按順序排好，準備讓一個剛加入的陌生人，看見三種沒有回來的孩子。", background: Background.Chapter_11_Ch11_Act4_S0 },
];
